#!/usr/bin/env node
/**
 * `npm publish` entry point (via `prepublishOnly`).
 *
 * `dist/` ships verbatim inside the npm tarball (see `files` in
 * package.json) — it's built once here, on the maintainer's machine, and
 * never regenerated by `npm install` on an end user's machine. If the
 * gapless symlink swap (scripts/lib/gapless-symlink-swap.mjs) were allowed to
 * run here, and the maintainer's machine supports symlinks (any non-Windows
 * box), `dist/server/defaults`/`dist/server/builtin-packs/market-packs`
 * would themselves be symlinks in the published tarball — and whether THAT
 * survives npm's tar extraction on a Windows *end user's* machine is a
 * separate, unverified question this process has no way to probe. So the
 * published tree must never contain one of these symlinks, independent of
 * what machine cut the release: force `BOBBIT_DIST_NO_SYMLINK=1` here, which
 * makes the capability probe report "unsupported" unconditionally and keeps
 * `npm run build:server` on the plain atomicReplaceDir (real directory)
 * fallback for this one invocation.
 */
import { execFileSync } from "node:child_process";

execFileSync("npm", ["run", "build"], {
  stdio: "inherit",
  shell: true, // Windows resolves the `npm` shim (npm.cmd) via a shell, not execFileSync's default PATH lookup.
  env: { ...process.env, BOBBIT_DIST_NO_SYMLINK: "1" },
});
